import{_ as d,o,c as e,a2 as s}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"PAPI 变量","description":"","frontmatter":{},"headers":[],"relativePath":"gtcommission/placeholders.md","filePath":"gtcommission/placeholders.md","lastUpdated":1784248671000}'),a={name:"gtcommission/placeholders.md"};function c(i,t,n,r,l,_){return o(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="papi-变量" tabindex="-1">PAPI 变量 <a class="header-anchor" href="#papi-变量" aria-label="Permalink to &quot;PAPI 变量&quot;">​</a></h1><p>变量标识为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtcommission</span></span></code></pre></div><p>使用示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%gtcommission_daily_complete%</span></span>
<span class="line"><span>%gtcommission_board_weekly_reset_time%</span></span>
<span class="line"><span>%gtcommission_economy_balance_points%</span></span></code></pre></div><p>面板 ID、任务 ID、经济 ID 和悬赏编号直接接在变量后面。ID 中包含下划线也可以正常识别。</p><h2 id="默认面板" tabindex="-1">默认面板 <a class="header-anchor" href="#默认面板" aria-label="Permalink to &quot;默认面板&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>返回内容</th></tr></thead><tbody><tr><td><code>%gtcommission_boards%</code></td><td>已开启的面板 ID，逗号分隔</td></tr><tr><td><code>%gtcommission_pool%</code></td><td>当前任务池 ID</td></tr><tr><td><code>%gtcommission_pool_name%</code></td><td>当前任务池名称</td></tr><tr><td><code>%gtcommission_daily_total%</code></td><td>当前任务总数</td></tr><tr><td><code>%gtcommission_daily_complete%</code></td><td>已完成任务数</td></tr><tr><td><code>%gtcommission_daily_claimed%</code></td><td>已领取任务数</td></tr><tr><td><code>%gtcommission_streak%</code></td><td>连续完成周期数</td></tr><tr><td><code>%gtcommission_reset_seconds%</code></td><td>距离下次刷新秒数</td></tr><tr><td><code>%gtcommission_reset_time%</code></td><td>距离下次刷新的中文时间</td></tr></tbody></table><h2 id="指定面板" tabindex="-1">指定面板 <a class="header-anchor" href="#指定面板" aria-label="Permalink to &quot;指定面板&quot;">​</a></h2><p>把 <code>&lt;面板ID&gt;</code> 换成 <code>boards/</code> 中的面板 ID：</p><table tabindex="0"><thead><tr><th>变量</th><th>返回内容</th></tr></thead><tbody><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_name%</code></td><td>面板名称</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_pool%</code></td><td>当前任务池 ID</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_pool_name%</code></td><td>当前任务池名称</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_total%</code></td><td>任务总数</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_complete%</code></td><td>已完成数量</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_claimed%</code></td><td>已领取数量</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_streak%</code></td><td>连续完成周期数</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_reset_seconds%</code></td><td>距离刷新秒数</td></tr><tr><td><code>%gtcommission_board_&lt;面板ID&gt;_reset_time%</code></td><td>距离刷新的中文时间</td></tr></tbody></table><p>指定面板中的任务：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%gtcommission_board_&lt;面板ID&gt;_progress_&lt;任务ID&gt;%</span></span>
<span class="line"><span>%gtcommission_board_&lt;面板ID&gt;_required_&lt;任务ID&gt;%</span></span>
<span class="line"><span>%gtcommission_board_&lt;面板ID&gt;_state_&lt;任务ID&gt;%</span></span></code></pre></div><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%gtcommission_board_weekly_progress_dungeon_clear%</span></span>
<span class="line"><span>%gtcommission_board_blacksmith_state_submit_logs%</span></span></code></pre></div><h2 id="默认面板任务" tabindex="-1">默认面板任务 <a class="header-anchor" href="#默认面板任务" aria-label="Permalink to &quot;默认面板任务&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>返回内容</th></tr></thead><tbody><tr><td><code>%gtcommission_daily_progress_&lt;任务ID&gt;%</code></td><td>当前进度</td></tr><tr><td><code>%gtcommission_daily_required_&lt;任务ID&gt;%</code></td><td>所需进度</td></tr><tr><td><code>%gtcommission_daily_state_&lt;任务ID&gt;%</code></td><td>进行中、待领取或已领取</td></tr><tr><td><code>%gtcommission_daily_name_&lt;任务ID&gt;%</code></td><td>任务名称</td></tr><tr><td><code>%gtcommission_daily_type_&lt;任务ID&gt;%</code></td><td>任务类型</td></tr></tbody></table><p>任务没有被该玩家当前面板抽中时，进度和需求返回 <code>0</code>，状态返回空文本。</p><h2 id="经济变量" tabindex="-1">经济变量 <a class="header-anchor" href="#经济变量" aria-label="Permalink to &quot;经济变量&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>返回内容</th></tr></thead><tbody><tr><td><code>%gtcommission_economies%</code></td><td>已配置的经济 ID</td></tr><tr><td><code>%gtcommission_economy_name_&lt;经济ID&gt;%</code></td><td>经济显示名称</td></tr><tr><td><code>%gtcommission_economy_available_&lt;经济ID&gt;%</code></td><td>当前是否可用，返回 <code>true</code> 或 <code>false</code></td></tr><tr><td><code>%gtcommission_economy_balance_&lt;经济ID&gt;%</code></td><td>玩家余额</td></tr></tbody></table><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%gtcommission_economy_name_money%</span></span>
<span class="line"><span>%gtcommission_economy_balance_points%</span></span></code></pre></div><h2 id="悬赏统计" tabindex="-1">悬赏统计 <a class="header-anchor" href="#悬赏统计" aria-label="Permalink to &quot;悬赏统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>返回内容</th></tr></thead><tbody><tr><td><code>%gtcommission_bounty_available%</code></td><td>当前开放悬赏数量</td></tr><tr><td><code>%gtcommission_bounty_accepted%</code></td><td>玩家当前接取数量</td></tr><tr><td><code>%gtcommission_bounty_published%</code></td><td>玩家发布过的悬赏数量</td></tr><tr><td><code>%gtcommission_bounty_completed%</code></td><td>玩家完成的悬赏数量</td></tr></tbody></table><h2 id="指定悬赏" tabindex="-1">指定悬赏 <a class="header-anchor" href="#指定悬赏" aria-label="Permalink to &quot;指定悬赏&quot;">​</a></h2><p>把 <code>&lt;悬赏编号&gt;</code> 换成悬赏 GUI 中显示的完整编号：</p><table tabindex="0"><thead><tr><th>变量</th><th>返回内容</th></tr></thead><tbody><tr><td><code>%gtcommission_bounty_progress_&lt;悬赏编号&gt;%</code></td><td>当前玩家在该悬赏中的总进度</td></tr><tr><td><code>%gtcommission_bounty_required_&lt;悬赏编号&gt;%</code></td><td>全部需求总数</td></tr><tr><td><code>%gtcommission_bounty_target_&lt;悬赏编号&gt;%</code></td><td>目标说明</td></tr><tr><td><code>%gtcommission_bounty_reward_&lt;悬赏编号&gt;%</code></td><td>奖励说明</td></tr><tr><td><code>%gtcommission_bounty_publisher_&lt;悬赏编号&gt;%</code></td><td>发布者名称</td></tr><tr><td><code>%gtcommission_bounty_economy_&lt;悬赏编号&gt;%</code></td><td>经济 ID</td></tr><tr><td><code>%gtcommission_bounty_currency_&lt;悬赏编号&gt;%</code></td><td>经济显示名称</td></tr><tr><td><code>%gtcommission_bounty_deposit_&lt;悬赏编号&gt;%</code></td><td>接取押金</td></tr><tr><td><code>%gtcommission_bounty_tip_&lt;悬赏编号&gt;%</code></td><td>每份小费</td></tr><tr><td><code>%gtcommission_bounty_shares_&lt;悬赏编号&gt;%</code></td><td>总份数</td></tr><tr><td><code>%gtcommission_bounty_winners_&lt;悬赏编号&gt;%</code></td><td>已完成份数</td></tr><tr><td><code>%gtcommission_bounty_hunters_&lt;悬赏编号&gt;%</code></td><td>当前接取人数</td></tr><tr><td><code>%gtcommission_bounty_state_&lt;悬赏编号&gt;%</code></td><td>悬赏状态</td></tr><tr><td><code>%gtcommission_bounty_expires_&lt;悬赏编号&gt;%</code></td><td>剩余秒数</td></tr><tr><td><code>%gtcommission_bounty_requirement_count_&lt;悬赏编号&gt;%</code></td><td>需求种类数量</td></tr><tr><td><code>%gtcommission_bounty_requirements_&lt;悬赏编号&gt;%</code></td><td>全部需求摘要</td></tr></tbody></table><h2 id="无-placeholderapi-时" tabindex="-1">无 PlaceholderAPI 时 <a class="header-anchor" href="#无-placeholderapi-时" aria-label="Permalink to &quot;无 PlaceholderAPI 时&quot;">​</a></h2><p>委托、悬赏和原版进度仍可正常使用，但 <code>%xxx%</code> 不会被其他插件解析，自定义经济的余额变量也无法读取。使用 PAPI 条件或自定义经济时必须安装 PlaceholderAPI。</p>`,29)])])}const g=d(a,[["render",c]]);export{p as __pageData,g as default};
